- name: Determine git context
  id: context
  env:
    INPUT_BRANCH: ${{ github.event.inputs.branch }}
    INPUT_TAG: ${{ github.event.inputs.tag }}
    INPUT_PR: ${{ github.event.inputs.pr_number }}
    GH_SHA: ${{ github.sha }}
    GH_EVENT: ${{ github.event_name }}
    GH_HEAD_REF: ${{ github.head_ref }}
    GH_REF: ${{ github.ref }}
    GH_REF_NAME: ${{ github.ref_name }}
    GH_PR_NUMBER: ${{ github.event.pull_request.number }}
  run: |
    # Use workflow_dispatch inputs if provided, otherwise derive from git context
    BRANCH="${INPUT_BRANCH}"
    TAG="${INPUT_TAG}"
    PR="${INPUT_PR}"
    SHA="${GH_SHA}"

    # If no override, detect branch from GITHUB_REF
    if [ -z "$BRANCH" ]; then
      if [ "$GH_EVENT" = "pull_request" ]; then
        BRANCH="${GH_HEAD_REF}"
        PR="${GH_PR_NUMBER}"
      elif [[ "$GH_REF" == refs/tags/* ]]; then
        TAG="${GH_REF_NAME}"
        BRANCH=""
      else
        BRANCH="${GH_REF_NAME}"
      fi
    fi

